import base64

def test_create_item(client, auth_headers, db):
    # First create a category
    cat_res = client.post("/api/v1/categories/", json={"name": "Tools"}, headers=auth_headers)
    assert cat_res.status_code == 200
    category_id = cat_res.json()["id"]

    # Tiny valid 1x1 black JPEG in base64
    photo_b64 = "data:image/jpeg;base64,"

    item_data = {
        "name": "Hammer",
        "item_code": "HM001",
        "category_id": category_id,
        "stock": 10,
        "photo_base64": photo_b64,
        "photo_content_type": "image/jpeg"
    }

    response = client.post("/api/v1/items/", json=item_data, headers=auth_headers)
    assert response.status_code == 200
    data = response.json()
    assert data["name"] == "Hammer"
    assert data["item_code"] == "HM001"
    assert data["has_photo"] is True

def test_get_items(client, auth_headers):
    response = client.get("/api/v1/items/", headers=auth_headers)
    assert response.status_code == 200
    assert isinstance(response.json(), list)
